const products = $input.first().json.products || [];
const threshold = parseInt($env.LOW_STOCK_THRESHOLD || '5', 10);

const lowStock = [];

for (const product of products) {
  for (const variant of (product.variants || [])) {
    const qty = parseInt(variant.inventory_quantity || '0', 10);
    if (qty <= threshold && variant.inventory_management === 'shopify') {
      lowStock.push({
        product_title: product.title,
        variant_title: variant.title !== 'Default Title' ? variant.title : '',
        sku: variant.sku || 'N/A',
        inventory_quantity: qty,
        price: variant.price
      });
    }
  }
}

if (lowStock.length === 0) {
  return [{ json: { has_alerts: false, message: 'All stock levels OK' } }];
}

let alertHtml = '<table border="1" cellpadding="8" cellspacing="0"><tr><th>Product</th><th>Variant</th><th>SKU</th><th>Stock</th><th>Price</th></tr>';
for (const item of lowStock) {
  const color = item.inventory_quantity <= 0 ? 'red' : 'orange';
  alertHtml += `<tr><td>${item.product_title}</td><td>${item.variant_title}</td><td>${item.sku}</td><td style="color:${color}"><strong>${item.inventory_quantity}</strong></td><td>${item.price}</td></tr>`;
}
alertHtml += '</table>';

return [{
  json: {
    has_alerts: true,
    low_stock_count: lowStock.length,
    out_of_stock: lowStock.filter(i => i.inventory_quantity <= 0).length,
    alert_html: alertHtml,
    checked_at: new Date().toISOString()
  }
}];
